import React, { useEffect, useState } from 'react';
import styled from 'styled-components';
import { MdSearch } from 'react-icons/md';
import SectionTitle from '../components/SectionTitle';
import PublicationsInfo from '../assets/data/publications';
import PublicationsItem from '../components/PublicationsItem';
import Footer from '../components/Footer';


const PublicationsStyle = styled.div`
  padding: 10rem 0;
  .publications__allItems {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(300px, 1fr));
    gap: 5rem;
    margin-top: 5rem;
  }
  .publications__searchBar {
    position: relative;
    width: 300px;
    margin-top: 5rem;
  }
  .publications__searchBar input {
    width: 100%;
    font-size: 2rem;
    padding: 0.8rem;
    color: var(--black);
    border-radius: 6px;
    outline: none;
    border: none;
  }
  .publications__searchBar .searchIcon {
    position: absolute;
    width: 2rem;
    right: 1rem;
  }
  .publications__searchBar .searchIcon path {
    color: var(--deep-dark);
  }
  @media only screen and (max-width: 768px) {
    .projects__searchBar,
    .projects__searchBar form,
    .projects__searchBar input {
      width: 100%;
    }
  }
`;

export default function Publications() {
  const [searchText, setSearchText] = useState('');
  const [publicationsData, setPublicationsData] = useState(PublicationsInfo);
  useEffect(() => {
    if (searchText === '') return;
    setPublicationsData(() =>
      PublicationsInfo.filter((item) =>
        item.name.toLowerCase().match(searchText.toLowerCase())
      )
    );
  }, [searchText]);
  const handleChange = (e) => {
    e.preventDefault();
    setSearchText(e.target.value);
    if (!e.target.value.length > 0) {
      setPublicationsData(PublicationsInfo);
    }
  };
  return (
    <>
      <PublicationsStyle>
        <div className="container">
          <SectionTitle
            heading="Papers and Publications"
            subheading="some of my recent"
          />
          <div className="publications__searchBar">
            <form>
              <input
                type="text"
                value={searchText}
                onChange={handleChange}
                placeholder="Publication Name"
              />
              <MdSearch className="searchIcon" />
            </form>
          </div>
          <div className="publications__allItems">
            {publicationsData.map((item) => (
              <PublicationsItem
                key={item.id}
                title={item.name}
                desc={item.desc}
                img={item.img}
                link={item.link}
              />
            ))}
          </div>
        </div>
      </PublicationsStyle>
      <Footer />
    </>
  );
}
